const pipe = (...fns) => x => fns.reduce((v, f) => f(v), x)

const normalize = user => ({ ...user, email: user.email.toLowerCase() })
const addRole = user => ({ ...user, role: user.role || 'user' })
const trim = user => ({ ...user, name: user.name.trim() })

const processUser = pipe(normalize, trim, addRole)

const result = processUser({
  email: 'Alice@Example.COM',
  name: '  Алиса  ',
  role: null
})
